def partitionEqualSubsetSum(data):
    nums = list(map(int, data.split()))
    total_sum = sum(nums)
    if total_sum % 2 != 0:
        return False
    target = total_sum // 2

    def can_partition(index, current_sum):
        if current_sum == target:
            return True
        if index >= len(nums) or current_sum > target:
            return False
        return can_partition(index + 1, current_sum + nums[index]) or can_partition(index + 1, current_sum)

    return can_partition(0, 0)

