class Solution {
    public boolean partitionEqualSubsetSum(int[] data) {
        int totalSum = 0;
        for (int num : data) {
            totalSum += num;
        }
        if (totalSum % 2 != 0) {
            return false;
        }
        return canPartition(data, totalSum / 2, 0);
    }
    private boolean canPartition(int[] data, int target, int index) {
        if (target == 0) {
            return true;
        }
        if (index >= data.length || target < 0) {
            return false;
        }
        // Include the current element
        if (canPartition(data, target - data[index], index + 1)) {
            return true;
        }
        // Exclude the current element
        return canPartition(data, target, index + 1);
    }
}

